  .slide-4 { background: var(--bg-dark); }
  .slide-4 .slide-label { color: var(--accent-green); }
  .slide-4 .compare-cols {
    display: flex;
    gap: 28px;
    margin-bottom: 24px;
  }
  .slide-4 .compare-col {
    flex: 1;
    min-width: 0;
    background: var(--bg-card);
    border-radius: 16px;
    padding: 36px 32px;
  }
  .slide-4 .compare-col h3 {
    font-size: 24px;
    font-weight: 700;
    margin-bottom: 24px;
  }
  .slide-4 .step-item {
    font-size: 22px;
    color: var(--text-secondary);
    line-height: 1.5;
    padding: 12px 0;
    border-bottom: 1px solid rgba(51,65,85,0.5);
    display: flex;
    gap: 12px;
    align-items: center;
  }
  .slide-4 .step-item:last-child { border-bottom: none; }
  .slide-4 .step-num {
    font-size: 18px;
    font-weight: 700;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    background: rgba(255,255,255,0.06);
  }
  .slide-4 .loop-insight {
    background: rgba(16,185,129,0.08);
    border: 1px solid rgba(16,185,129,0.25);
    border-radius: 16px;
    padding: 40px 40px;
    font-size: 28px;
    font-weight: 500;
    color: var(--text-primary);
    line-height: 1.6;
  }

  /* ════════════════════════════════════════════════════ */
  /* SLIDE 5 — FIRST REAL TEST                          */
  /* ════════════════════════════════════════════════════ */
  .slide-5 { background: var(--bg-dark); }
  .slide-5 .slide-label { color: var(--accent-purple); }
